mapper.select:
SELECT sis.id as sis_id, sis.student_id as sis_student_id, sis.status as sis_status, sis.company_id as sis_company_id, sis.position_id as sis_position_id, sis.has_complaint as sis_has_complaint, sis.is_delayed as sis_is_delayed, sis.is_interrupted as sis_is_interrupted, sis.create_time as sis_create_time, sis.update_time as sis_update_time, sis.recall_status as sis_recall_status, sis.recall_reason as sis_recall_reason, sis.recall_apply_time as sis_recall_apply_time, sis.recall_audit_time as sis_recall_audit_time, sis.recall_reviewer_id as sis_recall_reviewer_id, sis.recall_audit_remark as sis_recall_audit_remark, sis.company_confirm_status as sis_company_confirm_status, sis.internship_start_time as sis_internship_start_time, sis.internship_end_time as sis_internship_end_time, sis.internship_duration as sis_internship_duration, sis.feedback as sis_feedback, sis.remark as sis_remark, sis.student_name as sis_student_name, sis.gender as sis_gender, sis.grade as sis_grade, sis.major_name as sis_major_name, sis.class_name as sis_class_name, sis.contact_phone as sis_contact_phone, sis.email as sis_email, sis.company_name as sis_company_name, sis.position_name as sis_position_name, sis.company_address as sis_company_address, sis.company_phone as sis_company_phone, su.id as su_id, su.name as su_name, su.student_user_id as su_student_id, su.gender as su_gender, su.grade as su_grade, su.major_id as su_major_id, su.class_id as su_class_id, cls.id as cls_id, cls.name as cls_name, m.id as m_id, m.name as m_name, c.id as c_id, c.company_name as c_company_name, c.contact_person as c_contact_person, c.contact_phone as c_contact_phone, c.contact_email as c_contact_email, c.address as c_address, p.id as p_id, p.position_name as p_position_name, p.requirements as p_requirements, p.planned_recruit as p_planned_recruit, p.recruited_count as p_recruited_count, p.remaining_quota as p_remaining_quota FROM student_internship_status sis LEFT JOIN student_users su ON sis.student_id = su.id LEFT JOIN class cls ON su.class_id = cls.id LEFT JOIN major m ON su.major_id = m.id LEFT JOIN company_users c ON sis.company_id = c.id LEFT JOIN position p ON sis.position_id = p.id
AND su.id = #{studentId}
AND su.name LIKE CONCAT('%', #{name}, '%')
AND su.gender = #{gender}
AND sis.status = #{status}
AND sis.company_id = #{companyId}
AND c.company_name LIKE CONCAT('%', #{companyName}, '%')
AND su.grade = REPLACE(#{grade}, '级', '')
AND m.name = #{major}
AND cls.name = #{className}
AND su.student_user_id = #{studentUserId}
ORDER BY sis.create_time DESC

SELECT COUNT(*) FROM student_internship_status sis
INNER JOIN student_users su ON sis.student_id = su.id
WHERE su.major_id = #{majorId} AND sis.status = #{status}

SELECT su.student_user_id AS studentUserId, su.name AS studentName, m.name AS majorName, c.name AS className, CASE sis.status WHEN 0 THEN '未找到实习' WHEN 1 THEN '有Offer未确定' WHEN 2 THEN '已确定实习' WHEN 3 THEN '实习结束' ELSE '未知' END AS statusText, co.company_name AS companyName, p.position_name AS positionName, sis.update_time AS updatedTime FROM student_users su LEFT JOIN student_internship_status sis ON su.id = sis.student_id LEFT JOIN major m ON su.major_id = m.id LEFT JOIN class c ON su.class_id = c.id LEFT JOIN company_users co ON sis.company_id = co.id LEFT JOIN position p ON sis.position_id = p.id
sis.status = #{status}
ORDER BY m.name, c.name, su.student_user_id

SELECT sis.id as sis_id, sis.student_id as sis_student_id, sis.status as sis_status, sis.company_id as sis_company_id, sis.position_id as sis_position_id, sis.has_complaint as sis_has_complaint, sis.is_delayed as sis_is_delayed, sis.is_interrupted as sis_is_interrupted, sis.create_time as sis_create_time, sis.update_time as sis_update_time, sis.recall_status as sis_recall_status, sis.recall_reason as sis_recall_reason, sis.recall_apply_time as sis_recall_apply_time, sis.recall_audit_time as sis_recall_audit_time, sis.recall_reviewer_id as sis_recall_reviewer_id, sis.recall_audit_remark as sis_recall_audit_remark, sis.company_confirm_status as sis_company_confirm_status, sis.internship_start_time as sis_internship_start_time, sis.internship_end_time as sis_internship_end_time, sis.internship_duration as sis_internship_duration, sis.feedback as sis_feedback, sis.remark as sis_remark, sis.student_name as sis_student_name, sis.gender as sis_gender, sis.grade as sis_grade, sis.major_name as sis_major_name, sis.class_name as sis_class_name, sis.contact_phone as sis_contact_phone, sis.email as sis_email, sis.company_name as sis_company_name, sis.position_name as sis_position_name, sis.company_address as sis_company_address, sis.company_phone as sis_company_phone, su.id as su_id, su.name as su_name, su.student_user_id as su_student_id, su.gender as su_gender, su.grade as su_grade, su.major_id as su_major_id, su.class_id as su_class_id, cls.id as cls_id, cls.name as cls_name, m.id as m_id, m.name as m_name, c.id as c_id, c.company_name as c_company_name, c.contact_person as c_contact_person, c.contact_phone as c_contact_phone, c.contact_email as c_contact_email, c.address as c_address, p.id as p_id, p.position_name as p_position_name, p.requirements as p_requirements, p.planned_recruit as p_planned_recruit, p.recruited_count as p_recruited_count, p.remaining_quota as p_remaining_quota FROM student_internship_status sis LEFT JOIN student_users su ON sis.student_id = su.id LEFT JOIN class cls ON su.class_id = cls.id LEFT JOIN major m ON su.major_id = m.id LEFT JOIN company_users c ON sis.company_id = c.id LEFT JOIN position p ON sis.position_id = p.id WHERE sis.recall_status = 1
AND su.id = #{studentId}
AND su.name LIKE CONCAT('%', #{name}, '%')
AND su.gender = #{gender}
AND sis.company_id = #{companyId}
AND c.company_name LIKE CONCAT('%', #{companyName}, '%')
ORDER BY sis.recall_apply_time DESC
